import React, { Component } from 'react';
import './App.css';
import Navbar from './Components/Navbar/Navbar.js';
import TrendingUpdate from './Components/MainContainer/TrendingUpdate.js';
import WeeklyTop from './Components/MainContainer/WeeklyTop.js';
import RecentlyUpdate from './Components/MainContainer/RecentlyUpdate.js';
class App extends Component {
  render() {
    return (
      <div className="App">
          <Navbar></Navbar>
          <header>
           <div className="main-container">
              <TrendingUpdate></TrendingUpdate>
              <WeeklyTop></WeeklyTop>
           </div>
          </header>
      </div>
    );
  }
}

export default App;
